{"code": "import json
import urllib.request
import os
from datetime import datetime

# GitHub API 配置
GITHUB_API_BASE = "https://api.github.com"

def github_request(path, params=""):
    """Generic GitHub API request"""
    url = f"{GITHUB_API_BASE}{path}?{params}"
    try:
        with urllib.request.urlopen(url, timeout=10) as resp:
            return json.loads(resp.read().decode())
    except Exception as e:
        return {"error": str(e)}

def search_repositories(query, sort="stars", order="desc", per_page=10):
    """Search GitHub repositories"""
    params = f"q={query}&sort={sort}&order={order}&per_page={per_page}"
    return github_request("/search/repositories", params)

def get_trending_repositories(language="python", since="daily"):
    """Get trending repositories by language"""
    params = f"q=language:{language}&sort=stars&order=desc&since={since}"
    return github_request("/search/repositories", params)

# 搜索趋势 AI Agent 项目
print("=== Trending AI Agent Repositories (Python) ===\n")
trending = get_trending_repositories(language="python", since="weekly")
if "items" in trending:
    for i, repo in enumerate(trending["items"][:5], 1):
        print(f"{i}. {repo['name']} - {repo['description']}")
        print(f"   ⭐ {repo['stargazers_count']} | 📦 {repo['language']}")
        print(f"   📅 Updated: {repo['updated_at'][:10]}")
        print(f"   🔗 {repo['html_url']}\n")
else:
    print(f"Error: {trending.get('error', 'Unknown error')}")

# 搜索 self-improving agent 相关技能
print("\n=== GitHub Skills Search (self-improving agent) ===\n")
skills = search_repositories("self-improving-agent", per_page=5)
if "items" in skills:
    for repo in skills["items"]:
        print(f"• {repo['full_name']}: {repo['description']}")
        print(f"  ⭐ {repo['stargazers_count']}")"}

{"code": "import json
import urllib.request
import re
from datetime import datetime

def extract_readme(owner, repo):
    """Extract README content from GitHub repo"""
    url = f"https://raw.githubusercontent.com/{owner}/{repo}/main/README.md"
    try:
        with urllib.request.urlopen(url, timeout=10) as resp:
            return resp.read().decode()
    except:
        # Try master branch
        url = f"https://raw.githubusercontent.com/{owner}/{repo}/master/README.md"
        try:
            with urllib.request.urlopen(url, timeout=10) as resp:
                return resp.read().decode()
        except Exception as e:
            return f"Error: {e}"

def analyze_self_improvement(readme):
    """Analyze README for self-improvement capabilities"""
    lines = readme.split('\n')
    findings = {
        "has_memory": False,
        "has_learning": False,
        "has_evolution": False,
        "has_hooks": False,
        "key_patterns": []
    }

    for i, line in enumerate(lines):
        lower = line.lower()
        if 'memory' in lower:
            findings["has_memory"] = True
            if 'semantic' in lower or 'episodic' in lower or 'working' in lower:
                findings["key_patterns"].append(f"Memory architecture: {line.strip()}")
        if 'learn' in lower or 'evolve' in lower or 'improve' in lower:
            findings["has_learning"] = True
            findings["key_patterns"].append(f"Learning capability: {line.strip()}")
        if 'hook' in lower or 'trigger' in lower:
            findings["has_hooks"] = True
            findings["key_patterns"].append(f"Hook system: {line.strip()}")

    return findings

# Analyze trending repos
repos_to_analyze = [
    ("letta-ai", "letta"),
    ("facebookresearch", "HyperAgents"),
    ("agno-agi", "dash"),
    ("jennyzzt", "dgm")
]

print("=== GitHub Skills Analysis ===\n")

for owner, repo in repos_to_analyze:
    print(f"\n{'='*60}")
    print(f"Repo: {owner}/{repo}")
    print('='*60)

    readme = extract_readme(owner, repo)
    analysis = analyze_self_improvement(readme)

    print(f"\nSelf-Improvement Capabilities:")
    print(f"  Memory: {'✅' if analysis['has_memory'] else '❌'}")
    print(f"  Learning: {'✅' if analysis['has_learning'] else '❌'}")
    print(f"  Hooks: {'✅' if analysis['has_hooks'] else '❌'}")

    if analysis['key_patterns']:
        print(f"\nKey Patterns Found:")
        for pattern in analysis['key_patterns'][:3]:
            print(f"  • {pattern[:100]}...")"}

